/** Sanitises a raw placeId into a Firestore-safe doc id (matches the web app's safeId). */
export const SAFE_ID_PATTERN = /[^a-zA-Z0-9_-]/g;
export function safeId(id: string): string {
  return id.replace(SAFE_ID_PATTERN, "_");
}

